B.DF=new A.d_(983153,"MaterialIcons",null,!1)
B.D6=new A.cY("How do I create an account?",'Download the Harvest app, tap "Sign Up", enter your name, email, and a secure password. You\'ll receive a verification email to activate your account.')
B.Dg=new A.cY("I forgot my password. How do I reset it?",'On the Sign In screen, tap "Forgot password?" and enter your email. You\'ll receive a reset link within a few minutes.')
B.Db=new A.cY("How do I update my delivery address?","Go to Profile \u2192 Delivery Addresses to add, edit, or remove addresses. You can also set a default address for faster checkout.")
